mapper.sql:
from app.advisor_product
where creator_id = #{creatorId}

    and status = #{status}


    and type = #{type}


    and risk_level = #{riskLevel}


    and (
        name like concat('%', #{keyword}, '%')
        or strategy_code like concat('%', #{keyword}, '%')
    )

mapper.insert:
insert into app.advisor_product (
    name, type, risk_level, strategy_code, feature_tags, status, creator_id, current_version_no,
    published_version_no, last_reject_comment
) values (
    #{name}, #{type}, #{riskLevel}, #{strategyCode}, #{featureTags}, #{status}, #{creatorId}, #{currentVersionNo},
    #{publishedVersionNo}, #{lastRejectComment}
)

mapper.select:
select 

order by updated_at desc, id desc
limit #{pageSize} offset #{offset}
